import React, { useMemo } from "react";

const get = (obj, path, fallback = "") =>
  path.split(".").reduce((o, k) => (o && o[k] != null ? o[k] : null), obj) ?? fallback;

export default function Forecast({ daily = [] }) {
  const days = useMemo(() => daily.slice(0, 16), [daily]);

  return (
    <div>
      <h2 className="text-lg font-semibold mb-2">16‑Day Forecast</h2>

      {/* MOBILE: apple-style thin rectangles stacked */}
      <div className="space-y-2 sm:hidden">
        {days.map((d, i) => (
          <RowCard key={i} d={d} index={i} />
        ))}
      </div>

      {/* DESKTOP: compact grid, centered */}
      <div className="hidden sm:grid grid-cols-2 md:grid-cols-4 gap-3">
        {days.map((d, i) => (
          <SquareCard key={i} d={d} index={i} />
        ))}
      </div>
    </div>
  );
}

function RowCard({ d, index }) {
  const dt = get(d, "dt", Math.floor(Date.now()/1000) + (index+1)*86400);
  const day = new Date(dt*1000).toLocaleDateString([], { weekday: "short" });
  const tmin = Math.round(get(d, "temp.min", get(d, "tempMin", 0)));
  const tmax = Math.round(get(d, "temp.max", get(d, "tempMax", 0)));
  const icon = get(d, "weather.0.icon", "01d");

  return (
    <div className="w-full rounded-xl border border-white/10 bg-white/10 dark:bg-white/5 backdrop-blur p-3 flex items-center justify-between">
      <div className="w-16 text-sm opacity-80">{day}</div>
      <img alt="" className="w-8 h-8" src={`https://openweathermap.org/img/wn/${icon}.png`} />
      <div className="flex items-center gap-2 text-sm">
        <span className="font-medium">{tmax}°</span>
        <span className="opacity-70">{tmin}°</span>
      </div>
    </div>
  );
}

function SquareCard({ d, index }) {
  const dt = get(d, "dt", Math.floor(Date.now()/1000) + (index+1)*86400);
  const day = new Date(dt*1000).toLocaleDateString([], { weekday: "short" });
  const tmin = Math.round(get(d, "temp.min", get(d, "tempMin", 0)));
  const tmax = Math.round(get(d, "temp.max", get(d, "tempMax", 0)));
  const icon = get(d, "weather.0.icon", "01d");

  return (
    <div className="rounded-2xl p-4 shadow border border-white/10 bg-white/10 dark:bg-white/5 backdrop-blur flex flex-col items-center justify-center text-center">
      <div className="text-sm opacity-80 mb-1">{day}</div>
      <img alt="" className="w-10 h-10 mb-1" src={`https://openweathermap.org/img/wn/${icon}.png`} />
      <div className="text-sm"><span className="font-medium">{tmax}°</span> <span className="opacity-70">{tmin}°</span></div>
    </div>
  );
}
